import{_ as t,o as a,c as l,a0 as i}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Edit an Event Template","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/edit-event-template.md","filePath":"how-to/edit-event-template.md"}'),n={name:"how-to/edit-event-template.md"};function o(r,e,s,h,d,p){return a(),l("div",null,[...e[0]||(e[0]=[i('<h1 id="edit-an-event-template" tabindex="-1">Edit an Event Template <a class="header-anchor" href="#edit-an-event-template" aria-label="Permalink to &quot;Edit an Event Template&quot;">​</a></h1><p>Edit a template when you want to change how future instances, imports, and analytics for that event behave.</p><h2 id="what-you-can-change" tabindex="-1">What you can change <a class="header-anchor" href="#what-you-can-change" aria-label="Permalink to &quot;What you can change&quot;">​</a></h2><p>On the template detail and settings pages, you can adjust things like:</p><ul><li>name, icon, badge label, and colors</li><li>descriptions and instructions</li><li>score labels and limits</li><li>duration and stage behavior</li><li>membership and eligibility policies</li><li>dashboard and analytics visibility</li></ul><h2 id="where-to-edit" tabindex="-1">Where to edit <a class="header-anchor" href="#where-to-edit" aria-label="Permalink to &quot;Where to edit&quot;">​</a></h2><p>You usually work in two places:</p><ul><li>the template detail page for the main event identity</li><li>the event settings page for the deeper behavior and policy controls</li></ul><p>See <a href="./event-settings.html">Configure Event Settings</a> for the settings surface itself.</p><h2 id="default-templates-vs-custom-templates" tabindex="-1">Default templates vs custom templates <a class="header-anchor" href="#default-templates-vs-custom-templates" aria-label="Permalink to &quot;Default templates vs custom templates&quot;">​</a></h2><p>You can edit both default and custom templates, but there is one big difference:</p><ul><li>default templates are protected from deletion</li><li>custom templates can be deleted when policy allows it</li></ul><p>If you need a local version of a default event, use the <strong>Customize</strong> action to create a scoped copy.</p><h2 id="important-warning" tabindex="-1">Important warning <a class="header-anchor" href="#important-warning" aria-label="Permalink to &quot;Important warning&quot;">​</a></h2><p>Template changes are meant to shape future work. They should not be used with the expectation that old event history will be rewritten.</p><p>For example:</p><ul><li>changing a score label helps future clarity</li><li>changing import behavior helps future imports</li><li>old saved rows are still old saved rows</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./create-custom-event.html">Create a Custom Event</a></li><li><a href="./event-settings.html">Configure Event Settings</a></li><li><a href="./event-proposals.html">Propose &amp; Review Template Changes</a></li></ul>',19)])])}const m=t(n,[["render",o]]);export{u as __pageData,m as default};
